mapper.select:
SELECT A1.USER_ID
  FROM ARMUSER A1
 WHERE A1.CRTFC_DN_VALUE = #{crtfcDnValue}
   AND A1.USER_SE = #{userSe}
   AND IFNULL(A1.MBER_STTUS, '') <> 'D'
 LIMIT 1

mapper.update:
UPDATE ARMUSER
   SET PASSWORD = #{encryptedPassword}
     , CHG_PWD_LAST_PNTTM = NOW()
     , CHG_LAST_DT = NOW()
 WHERE ESNTL_ID = #{esntlId}
   AND IFNULL(MBER_STTUS, '') <> 'D'

mapper.select:
SELECT A1.ESNTL_ID
  FROM ARMUSER A1
 WHERE A1.NAVER_AUTH_ID = #{naverAuthId}
   AND A1.MBER_STTUS = 'P'
   AND A1.ESNTL_ID <> #{excludeEsntlId}
 LIMIT 1

SELECT A1.ESNTL_ID
  FROM ARMUSER A1
 WHERE A1.KAKAO_AUTH_ID = #{kakaoAuthId}
   AND A1.MBER_STTUS = 'P'
   AND A1.ESNTL_ID <> #{excludeEsntlId}
 LIMIT 1

mapper.update:
UPDATE ARMUSER
   SET OAUTH_GB = #{oauthGb}

     , NAVER_AUTH_ID = #{naverAuthId}


     , KAKAO_AUTH_ID = #{kakaoAuthId}

     , CHG_LAST_DT = NOW()
 WHERE ESNTL_ID = #{esntlId}

select.if:
SELECT MBER_ID 				AS ID
  FROM LETTNGNRLMBER
 WHERE MBER_NM = #{name}
   AND MBER_EMAIL_ADRES = #{email}
   AND MBER_STTUS = 'P'

SELECT ENTRPRS_MBER_ID 			AS ID
  FROM LETTNENTRPRSMBER
 WHERE CMPNY_NM = #{name}
   AND APPLCNT_EMAIL_ADRES = #{email}
   AND ENTRPRS_MBER_STTUS = 'P'

SELECT EMPLYR_ID 			AS ID
  FROM LETTNEMPLYRINFO
 WHERE DECRYPT(USER_NM) = #{name}
   AND EMAIL_ADRES = #{email}
   AND EMPLYR_STTUS_CODE = 'P'

SELECT PASSWORD 			AS PASSWORD
  FROM LETTNGNRLMBER
 WHERE MBER_ID = #{id}
   AND MBER_NM = #{name}
   AND MBER_EMAIL_ADRES = #{email}
   AND PASSWORD_HINT = #{passwordHint}
   AND PASSWORD_CNSR = #{passwordCnsr}
   AND MBER_STTUS = 'P'

SELECT ENTRPRS_MBER_PASSWORD 	AS PASSWORD
  FROM LETTNENTRPRSMBER
 WHERE ENTRPRS_MBER_ID = #{id}
   AND CMPNY_NM = #{name}
   AND APPLCNT_EMAIL_ADRES = #{email}
   AND ENTRPRS_MBER_PASSWORD_HINT = #{passwordHint}
   AND ENTRPRS_MBER_PASSWORD_CNSR = #{passwordCnsr}
   AND ENTRPRS_MBER_STTUS = 'P'

SELECT PASSWORD 			AS PASSWORD
  FROM LETTNEMPLYRINFO
 WHERE EMPLYR_ID = #{id}
   AND DECRYPT(USER_NM) = #{name}
   AND EMAIL_ADRES = #{email}
   AND PASSWORD_HINT = #{passwordHint}
   AND PASSWORD_CNSR = #{passwordCnsr}
   AND EMPLYR_STTUS_CODE = 'P'

update.if:
UPDATE LETTNGNRLMBER
   SET PASSWORD = #{password}
 WHERE MBER_ID = #{id}

UPDATE LETTNENTRPRSMBER
   SET ENTRPRS_MBER_PASSWORD = #{password}
 WHERE ENTRPRS_MBER_ID = #{id}

UPDATE LETTNEMPLYRINFO
   SET PASSWORD = #{password}
 WHERE EMPLYR_ID = #{id}
